Javascript.validate:
var val = Services.getValue(TPAmntToPay.dataBinding);
var err = validateCurrencyValue(val, 99999999.99 );
if( null == err )
{	Services.setValue(TPAmntToPay.dataBinding, WPU.formatToTwoDP(val));
}
return err;

