function DefaultCurrency504() {}
DefaultCurrency504.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency504.tabIndex = -1;
DefaultCurrency504.maxLength = 1;
DefaultCurrency504.isReadOnly = function(){return true;}
DefaultCurrency504.isTemporary = function(){return true;}
DefaultCurrency504.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency504.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
